module RefModule(
  clk, reset, D, Q
);parameter W = 16;

input clk;
input reset;
input signed [W:0] D;
output signed [W:0] Q;
reg signed [W:0] Q;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset)
      Q = 0;
    else
      Q = D;
  end
endmodule
